INSERT INTO `appointments` (`id`, `patient_id`, `doctor_id`, `department_id`, `appointment_date`, `duration`, `type`, `status`, `reason`, `notes`, `created_at`, `updated_at`) VALUES
('019c2474-a556-71a8-a690-8666fa2424eb', '019c2474-9b6b-7270-a745-041acbd7b241', '019b74cf-28ea-7366-8796-3700bdebebc5', '019b7d8f-9986-7005-b3d7-40df8787f17b', '2026-02-03 20:30:00', 30, 'Consultation', 'Confirmed', 'MEDICATION', NULL, '2026-02-03 17:02:30', '2026-02-03 17:06:07');
INSERT INTO `departments` (`id`, `name`, `description`, `head_doctor_id`, `consultation_fee`, `is_active`, `created_at`, `updated_at`) VALUES
('019b7d83-baa3-703e-a997-38be04334086', 'Outpatient Department (OPD)', 'The Outpatient Department (OPD) offers fast, patient-centered care without hospital admission. It provides consultations, tests, and minor treatments with a focus on accessible, quality healthcare.', NULL, 0.00, 1, '2026-01-02 07:02:23', '2026-01-02 07:04:31'),
('019b7d86-dc80-72a6-b1fb-17377071e4a7', 'Internal Medicine Department', 'The Internal Medicine Department provides expert adult care, focusing on preventing, diagnosing, and treating diseases of internal organs. It manages both acute and chronic conditions with personalized care to support long-term health.', NULL, 0.00, 1, '2026-01-02 07:05:48', '2026-01-02 07:05:48'),
('019b7d87-f8b9-7289-9444-94d9379c7c17', 'Paediatrics Department', 'The Paediatrics Department offers comprehensive care for children from birth to adolescence, including check-ups, vaccinations, and illness treatment. It supports healthy growth and development by working closely with parents.', NULL, 0.00, 1, '2026-01-02 07:07:01', '2026-01-02 07:07:01'),
('019b7d8a-7f81-70ec-8f4e-d40be2700af8', 'Obstetrics and Gynaecology Department', 'Obstetrics and Gynaecology Department provides safe, personalized care for women’s health needs, covering pregnancy, childbirth, reproductive health, and gynecological conditions at every stage of life.', NULL, 0.00, 1, '2026-01-02 07:09:47', '2026-01-02 07:09:47'),
('019b7d8f-9986-7005-b3d7-40df8787f17b', 'Dermatology Department', 'The Dermatology Department offers expert diagnosis and treatment of skin, hair, and nail conditions, providing personalized care and advanced treatments for healthy, glowing skin.', NULL, 0.00, 1, '2026-01-02 07:15:21', '2026-01-02 07:15:21'),
('019b7d91-f360-72bf-a80f-ae013c636e23', 'Surgery Department', 'Surgery Department provides safe, professional surgical care with skilled staff and modern equipment, offering minor and major procedures along with thorough pre- and post-operative care for a smooth recovery.', NULL, 0.00, 1, '2026-01-02 07:17:55', '2026-01-02 07:17:55'),
('019b7d93-713a-7005-80f9-a9c42e90be3c', 'Geriatric Department', 'Geriatric Department provides specialized, personalized care for older adults, managing age-related conditions and chronic illnesses to help seniors remain healthy, active, and comfortable.', NULL, 0.00, 1, '2026-01-02 07:19:33', '2026-01-02 07:19:33'),
('019b7d95-2622-7151-8f0a-796099c209a6', 'Psychiatry Department', 'Our Psychiatry Department supports mental and emotional well-being for all ages. We offer diagnosis, counseling, and treatment for conditions like stress, anxiety, and depression in a safe, supportive, and stigma-free environment.', NULL, 0.00, 1, '2026-01-02 07:21:25', '2026-01-02 07:21:25');
